impl<R: SessionLimitProjectionRepository> SessionLimitEventHandler for SessionLimitProjector<R> {

    async fn on_created(&self, event: SessionLimitCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = SessionLimitProjection::new(
            event.id,
            event.user_id,
            event.max_sessions,
            event.max_sessions_per_device,
            event.enforce_limit,
            event.current_session_count,
            event.last_session_revoke_at,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: SessionLimitUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.max_sessions = event.max_sessions;
            projection.max_sessions_per_device = event.max_sessions_per_device;
            projection.enforce_limit = event.enforce_limit;
            projection.current_session_count = event.current_session_count;
            projection.last_session_revoke_at = event.last_session_revoke_at;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: SessionLimitDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

